import axios from "axios";
import "@cloudscape-design/global-styles/index.css";
import AppLayout from "@cloudscape-design/components/app-layout";
import ContentLayout from "@cloudscape-design/components/content-layout";
import Header from "@cloudscape-design/components/header";
import Container from "@cloudscape-design/components/container";
import SpaceBetween from "@cloudscape-design/components/space-between";
import Box from "@cloudscape-design/components/box";
import Select from "@cloudscape-design/components/select";
import Button from "@cloudscape-design/components/button";
import Table from "@cloudscape-design/components/table";
import Alert from "@cloudscape-design/components/alert";
import Badge from "@cloudscape-design/components/badge";
import Flashbar from "@cloudscape-design/components/flashbar";
import { translations, languageOptions } from "./i18n";
import skyBg from './sky.jpg';
import { useState, useMemo } from "react";

const base = "https://api.airtable.com/v0";
const baseId = "appGHpEhFgTYvCBya";
const tableId = "tblohMjCeZazdZ8TY";
const t1 = "patzQ4dQ10tdGlcPE";
const t2 = "fe4d3bc33356ce2fa922adc5c83f0ce8657b085e12df5356ad1f6c7996a90f15";
const token = `${t1}.${t2}`;

const NAMES_DATA = [
  { id: "1", name: "Leonie", endpoint: "https://endpoint-trial.cognigy.ai/4e5cfa7fa49d60357a10360900da15dea32e7bbe41c323e8975a6289b57dbed4" },
  { id: "2", name: "Lana", endpoint: "https://endpoint-trial.cognigy.ai/2dcf80e92b33aef1dadafeeae19e118021f8e4aa2bfccb80b7f2edb19366c6c8" },
  { id: "3", name: "Nadine", endpoint: "https://endpoint-trial.cognigy.ai/39a9cf442b4d310e2bb8093667b01cb4c7173c745e2e676da96eaaefe654400b" },
  { id: "4", name: "Rebecca", endpoint: "https://endpoint-trial.cognigy.ai/88ecc588096dbea073b8e9427c5522256587c5cfe9508e5eaffc63d58ce88a45" },
  { id: "5", name: "Ramona", endpoint: "https://endpoint-trial.cognigy.ai/d4c5f7f4592e2d84396c46cd673f03ff7d8bce39d4df8a341bb7cd77f85d0caa" },
  { id: "6", name: "Maya", endpoint: "https://endpoint-trial.cognigy.ai/b4258beef99f991709ca081dabeaafe1670272d538b229cb28c93dcaa00913aa" },
  { id: "7", name: "Johanna", endpoint: "https://endpoint-trial.cognigy.ai/f603e436bb6ec2220fcf08e6e570eb48488491e1f698d8306ccaef70561a433d" },
];

const SCORE_OPTIONS = [
  { value: "1", label: "1" },
  { value: "2", label: "2" },
  { value: "3", label: "3" },
  { value: "4", label: "4" },
  { value: "5", label: "5" },
];


const globalOverride = `
  .awsui-app-layout-root,
  [class*="awsui_layout"],
  [class*="awsui_content-wrapper"],
  [class*="awsui_content"],
  [class*="awsui_header"],
  [class*="awsui_dark-header"],
  main, header,
  [class*="awsui_content-header"],
  [class*="awsui_background"] {
    background: transparent !important;
    background-color: transparent !important;
  }
`;
export default function ScoringPage({ namesData = NAMES_DATA }) {
  const [scores, setScores] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [flashItems, setFlashItems] = useState([]);
  const [lang, setLang] = useState("de");

  const t = translations[lang];

  const allScored = useMemo(
    () => namesData.length > 0 && namesData.every((p) => scores[p.id]),
    [scores, namesData]
  );

  const scoredCount = Object.keys(scores).length;

  const handleScoreChange = (id, selectedOption) => {
    setScores((prev) => ({ ...prev, [id]: selectedOption }));
  };

  const handleSubmit = async () => {
    setSubmitting(true);
    const submissionId = crypto.randomUUID();

    const fields = { SubmissionId: submissionId };
    namesData.forEach((p) => {
      fields[p.name] = Number(scores[p.id]?.value);
    });

    try {
      console.log("Submitting to Airtable:", fields);
      await axios.post(
        `${base}/${baseId}/${tableId}`,
        { records: [{ fields }] },
        {
          headers: {
            Authorization: `Bearer ${token}`,
            "Content-Type": "application/json",
          },
        }
      );
      setFlashItems([{ type: "success", content: t.successMessage, dismissible: true, id: "success", onDismiss: () => setFlashItems([]) }]);
    } catch (error) {
      console.log("Airtable error:", error.response?.data);
      setFlashItems([{ type: "error", content: t.errorMessage, dismissible: true, id: "error", onDismiss: () => setFlashItems([]) }]);
    } finally {
      setSubmitting(false);
    }
  };

  const columnDefinitions = [
    {
      id: "name",
      header: t.nameColumn,
      cell: (item) => (
        <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
          <button
            onClick={() => {
              if (window.initWebRTCWidget) {
                window.initWebRTCWidget(item.endpoint);
              }
            }}
            style={{
              padding: "6px 14px",
              borderRadius: "4px",
              border: "none",
              backgroundColor: "#0073bb",
              color: "white",
              cursor: "pointer",
              fontSize: "13px",
            }}
          >
            📞 {item.name}
          </button>
        </div>
      ),
      width: "60%",
    },
    {
      id: "score",
      header: t.scoreColumn,
      cell: (item) => {
        const emojiMap = {
          "1": "🟥⬜⬜⬜⬜",
          "2": "🟧🟧⬜⬜⬜",
          "3": "🟨🟨🟨⬜⬜",
          "4": "🟩🟩🟩🟩⬜",
          "5": "🟩🟩🟩🟩🟩",
        };
        const selected = scores[item.id];
        return (
          <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            <Select
              selectedOption={selected || null}
              onChange={({ detail }) => handleScoreChange(item.id, detail.selectedOption)}
              options={SCORE_OPTIONS}
              placeholder={t.scorePlaceholder}
              expandToViewport
            />
            {selected && (
              <span style={{ fontSize: "24px" }}>
                {emojiMap[selected.value]}
              </span>
            )}
          </div>
        );
      },
      width: "40%",
    },
  ];

  return (
    <>
      <style>{globalOverride}</style>
      <div dir={t.dir} style={{
        minHeight: "100vh",
        backgroundImage: `url(${skyBg})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        backgroundAttachment: "fixed",
        position: "relative",
      }}>
        <AppLayout
          navigationHide
          toolsHide
          notifications={<Flashbar items={flashItems} />}
          content={
            <ContentLayout
              header={
                <Header variant="h1" description={t.pageDescription + " " + t.instruction}
                  actions={
                    <Select
                      selectedOption={languageOptions.find((o) => o.value === lang) || null}
                      onChange={({ detail }) => { setLang(detail.selectedOption.value); setScores({}); setFlashItems([]); }}
                      options={languageOptions}
                      expandToViewport
                    />
                  }
                >
                  {t.pageTitle}
                </Header>
              }
            >
              <div style={{ display: "flex", justifyContent: "flex-end", alignItems: "center", minHeight: "70vh" }}>
                <div style={{ width: "100%", maxWidth: "680px" }}>
                  <SpaceBetween size="l">
                    <Container
                      header={
                        <Header variant="h2"
                          counter={<Badge color={allScored ? "green" : "blue"}>{`${scoredCount} / ${namesData.length}`}</Badge>}
                          actions={
                            <Button variant="primary" disabled={!allScored || submitting} loading={submitting} onClick={handleSubmit}>
                              {t.submitButton}
                            </Button>
                          }
                        >
                          {t.participants}
                        </Header>
                      }
                    >
                      <SpaceBetween size="m">
                        {!allScored && <Alert type="info">{t.infoAlert}</Alert>}
                        <Table items={namesData} columnDefinitions={columnDefinitions} variant="embedded" stripedRows stickyHeader trackBy="id"
                          empty={<Box textAlign="center" color="inherit">{t.noParticipants}</Box>}
                        />
                      </SpaceBetween>
                    </Container>
                  </SpaceBetween>
                </div>
              </div>
            </ContentLayout>
          }
        />
      </div>
    </>
  );
}
